/**
 * @fileoverview Swipe view — DOM construction, UI updates, visual effects.
 * @module module/Swipe/view
 */

import razyui from '../../index.js';
import { ARIA, ARROWS, PART }        from './constants.js';
import { dotPositionClass,
         cardLayoutInfo,
         cardOffsetFor }        from './helpers.js';

// ═══════════════════════════════════════════════
//  DOM Construction
// ═══════════════════════════════════════════════

/**
 * Create a track element and move container children into it.
 *
 * @param {HTMLElement} container
 * @param {string} trackClassName — e.g. 'swipe-track' or 'swipe-track swipe-card-track'
 * @param {string} panelClass — class to add to each child, e.g. 'swipe-panel'
 * @param {string} [extraPanelClass] — optional extra class per panel
 * @returns {{ track: HTMLElement, panels: HTMLElement[], count: number }}
 */
export function buildTrack(container, trackClassName, panelClass, extraPanelClass) {
    const track = razyui.el('div', { className: trackClassName });
    PART.TRACK.apply(track);
    if (trackClassName.includes('swipe-card-track')) PART.CARD_TRACK.apply(track);
    if (trackClassName.includes('swipe-snap-track')) PART.SNAP_TRACK.apply(track);

    const children = Array.from(container.children);
    children.forEach(child => {
        const $child = razyui(child);
        $child.addClass(panelClass);
        if (extraPanelClass) $child.addClass(extraPanelClass);
        PART.PANEL.apply(child);
        if (extraPanelClass === 'swipe-card-panel') PART.CARD_PANEL.apply(child);
        track.append(child);
    });

    razyui(container).append(track);
    return { track, panels: Array.from(track[0].children), count: children.length };
}

/**
 * Create dot indicator elements.
 *
 * @param {number} count — number of dots
 * @param {string} dotPosition — e.g. 'bottom-center'
 * @param {string} labelPrefix — ARIA label prefix (e.g. 'Slide', 'Page', 'Item')
 * @param {string} [extraClass] — optional extra CSS class on wrapper
 * @returns {HTMLElement} dots container element
 */
export function buildDots(count, dotPosition, labelPrefix, extraClass) {
    const dotsEl = razyui.el('div', { className: 'swipe-dots' });
    if (extraClass) dotsEl.addClass(extraClass);

    const posClass = dotPositionClass(dotPosition);
    if (posClass) dotsEl.addClass(posClass);
    PART.DOTS.apply(dotsEl);
    if (extraClass === 'swipe-card-dots') PART.CARD_DOTS.apply(dotsEl);
    if (extraClass === 'swipe-snap-dots') PART.SNAP_DOTS.apply(dotsEl);

    for (let i = 0; i < count; i++) {
        const dot = razyui.el('button', { className: 'swipe-dot', 'aria-label': `${labelPrefix} ${i + 1}` });
        PART.DOT.apply(dot);
        dotsEl.append(dot);
    }

    return dotsEl;
}

/**
 * Create prev / next navigation buttons.
 *
 * @returns {{ prevBtn: HTMLElement, nextBtn: HTMLElement }}
 */
export function buildButtons() {
    const prevBtn = razyui.el('button', { className: 'swipe-btn swipe-prev', 'aria-label': ARIA.PREV, innerHTML: ARROWS.PREV });
    PART.BTN.apply(prevBtn);

    const nextBtn = razyui.el('button', { className: 'swipe-btn swipe-next', 'aria-label': ARIA.NEXT, innerHTML: ARROWS.NEXT });
    PART.BTN.apply(nextBtn);

    return { prevBtn, nextBtn };
}

/**
 * Create sentinel clones for seamless infinite loop (slide mode).
 *
 * @param {HTMLElement} track
 * @param {HTMLElement[]} panels
 * @param {Function} makeCloneFn — `makeClone(el, cfg)`
 * @returns {HTMLElement[]} [lastClone, firstClone]
 */
export function createClones(track, panels, makeCloneFn) {
    const first = panels[0];
    const last  = panels[panels.length - 1];

    // Clone of last → prepend before first
    const lastClone = makeCloneFn(last);
    razyui(first).before(razyui(lastClone));

    // Clone of first → append after last
    const firstClone = makeCloneFn(first);
    track.append(firstClone);

    return [lastClone, firstClone];
}

// ═══════════════════════════════════════════════
//  UI Update Helpers
// ═══════════════════════════════════════════════

/**
 * Update dot active states.
 *
 * @param {HTMLElement|null} dotsEl
 * @param {number} activeIndex
 */
export function updateDots(dotsEl, activeIndex) {
    if (!dotsEl) return;
    Array.from(dotsEl[0].children).forEach((dot, i) => {
        const $dot = razyui(dot);
        $dot.toggleClass('is-active', i === activeIndex);
        $dot.setAttr({ 'aria-current': i === activeIndex ? 'true' : 'false' });
    });
}

/**
 * Update prev / next button visibility (non-loop mode).
 *
 * @param {HTMLElement|null} prevBtn
 * @param {HTMLElement|null} nextBtn
 * @param {number} index — current index
 * @param {number} maxIndex — last valid index
 * @param {boolean} loop
 */
export function updateButtons(prevBtn, nextBtn, index, maxIndex, loop) {
    if (loop) return;
    if (prevBtn) prevBtn.toggleClass('is-hidden', index === 0);
    if (nextBtn) nextBtn.toggleClass('is-hidden', index >= maxIndex);
}

/**
 * Update panels' active CSS class and aria-hidden attribute.
 *
 * @param {HTMLElement[]} panels
 * @param {number} activeIndex
 */
export function updatePanels(panels, activeIndex) {
    panels.forEach((p, i) => {
        const $p = razyui(p);
        $p.toggleClass('is-active', i === activeIndex);
        $p.setAttr({ 'aria-hidden': i !== activeIndex ? 'true' : 'false' });
    });
}

/**
 * Set the --swipe CSS custom property on the container.
 *
 * @param {HTMLElement} container
 * @param {number} value
 */
export function setSwipeProperty(container, value) {
    razyui(container).css('--swipe', value);
}

// ═══════════════════════════════════════════════
//  Track Transform (Slide mode)
// ═══════════════════════════════════════════════

/**
 * Animate the track to a computed position (slide mode snap).
 *
 * @param {HTMLElement} track
 * @param {number} target — translate value in px
 * @param {boolean} isH — horizontal?
 * @param {number} duration — ms
 * @param {string} easing — CSS easing
 * @param {boolean} animate
 */
export function trackSnapTo(track, target, isH, duration, easing, animate) {
    if (animate) {
        track.css('transition', `transform ${duration}ms`);
        const validEasing = /^(ease|linear|ease-in|ease-out|ease-in-out)$/.test(easing);
        track.css('transitionTimingFunction', validEasing ? easing : 'ease-out');
    } else {
        track.css('transition', 'none');
    }
    track.css('transform', isH
        ? `translate3d(${target}px, 0, 0)`
        : `translate3d(0, ${target}px, 0)`);
}

/**
 * Apply visual offset during drag (slide mode).
 *
 * @param {HTMLElement} track
 * @param {number} base — base offset from offsetFor()
 * @param {number} px — drag delta
 * @param {boolean} isH
 */
export function applyDragOffset(track, base, px, isH) {
    const value = base + px;
    track.css('transform', isH
        ? `translate3d(${value}px, 0, 0)`
        : `translate3d(0, ${value}px, 0)`);
}

/**
 * Instant reposition without animation (infinite loop clone swap).
 *
 * @param {HTMLElement} track
 * @param {number} target
 * @param {boolean} isH
 */
export function silentReposition(track, target, isH) {
    track.css({ transition: 'none', transform: isH
            ? `translate3d(${target}px, 0, 0)`
            : `translate3d(0, ${target}px, 0)` });
    void track.prop('offsetHeight');   // force reflow
}

// ═══════════════════════════════════════════════
//  Card Mode View
// ═══════════════════════════════════════════════

/**
 * Apply card positions and sizes to panels.
 *
 * @param {HTMLElement[]} panels
 * @param {object} cfg
 * @param {number} containerW
 * @param {number} count
 * @param {number} cols — effective columns
 * @param {HTMLElement} trackEl
 */
export function cardLayoutPanels(panels, cfg, containerW, count, cols, trackEl) {
    const info = cardLayoutInfo(cfg, containerW, count, cols);

    panels.forEach((p, i) => {
        razyui(p).css({
            position: 'absolute',
            left: '0',
            top: '0',
            width: info.cardW + 'px',
            height: '100%',
            transform: `translate3d(${info.positions[i]}px, 0, 0)`,
            transition: 'none',
        });
    });

    trackEl.css({ width: info.totalW + 'px', height: '100%', position: 'relative' });

    return info.positions;
}

/**
 * Snap card track to a page offset.
 *
 * @param {HTMLElement} track
 * @param {number} offset
 * @param {number} duration
 * @param {string} easing
 * @param {boolean} animate
 */
export function cardSnapTo(track, offset, duration, easing, animate) {
    if (animate) {
        track.css('transition', `transform ${duration}ms ${easing}`);
    } else {
        track.css('transition', 'none');
    }
    track.css('transform', `translate3d(${offset}px, 0, 0)`);
}

/**
 * Apply custom card animations for peek-in, peek-out, and moving cards.
 *
 * @param {HTMLElement[]} panels
 * @param {number} pageIndex
 * @param {object} cfg
 * @param {number} count
 * @param {number} cols
 * @param {number} step
 * @param {boolean} animate
 * @param {object} context — `this` context for callback invocation
 */
export function cardApplyAnimations(panels, pageIndex, cfg, count, cols, step, animate, context) {
    const startCard = pageIndex * step;
    const endCard   = Math.min(startCard + cols, count);
    const duration  = animate ? cfg.duration : 0;

    panels.forEach((p, i) => {
        const $p = razyui(p);
        // Set transition on the panel for custom animations
        if (animate) {
            $p.css('transition', `transform ${duration}ms ${cfg.easing}, opacity ${duration}ms ${cfg.easing}`);
        } else {
            $p.css('transition', 'none');
        }

        if (i >= startCard && i < endCard) {
            // ── Active / moving card ──
            $p.css('opacity', '1');
            $p.addClass('is-active');
            $p.removeClass('is-peek-in is-peek-out');
            if (typeof cfg.onCardMove === 'function') {
                const progress = (i - startCard) / Math.max(1, cols - 1);
                cfg.onCardMove.call(context, p, { index: i, page: pageIndex, slot: i - startCard, progress });
            }
        } else if (i === startCard - 1 || i === endCard) {
            // ── Peek card (adjacent to visible range) ──
            $p.css('opacity', cfg.cardPeek > 0 ? '1' : '0');
            $p.removeClass('is-active');
            if (i < startCard) {
                $p.addClass('is-peek-out');
                $p.removeClass('is-peek-in');
                if (typeof cfg.onCardPeekOut === 'function') {
                    cfg.onCardPeekOut.call(context, p, { index: i, direction: 'left' });
                }
            } else {
                $p.addClass('is-peek-in');
                $p.removeClass('is-peek-out');
                if (typeof cfg.onCardPeekIn === 'function') {
                    cfg.onCardPeekIn.call(context, p, { index: i, direction: 'right' });
                }
            }
        } else {
            // ── Far off-screen card ──
            $p.css('opacity', '0');
            $p.removeClass('is-active is-peek-in is-peek-out');
        }
    });
}

// ═══════════════════════════════════════════════
//  Snap Mode View
// ═══════════════════════════════════════════════

/**
 * Set the track position for snap mode centering.
 *
 * @param {HTMLElement} track
 * @param {number} offset
 * @param {boolean} isH
 * @param {number} duration
 * @param {string} easing
 * @param {boolean} animate
 */
export function snapApplyPosition(track, offset, isH, duration, easing, animate) {
    if (animate) {
        track.css('transition', `transform ${duration}ms ${easing}`);
    } else {
        track.css('transition', 'none');
    }
    track.css('transform', isH
        ? `translate3d(${offset}px, 0, 0)`
        : `translate3d(0, ${offset}px, 0)`);
}

/**
 * Toggle active class on snap-mode panels.
 *
 * @param {HTMLElement[]} panels
 * @param {number} activeIndex
 */
export function snapUpdatePanels(panels, activeIndex) {
    panels.forEach((p, i) => {
        razyui(p).toggleClass('is-active', i === activeIndex);
    });
}

// ═══════════════════════════════════════════════
//  Per-item Styling (itemStyle)
// ═══════════════════════════════════════════════

/**
 * Apply itemStyle rules to panels based on distance from the active index.
 * Supports fixed values per position key (0, 1, -1, 2, -2, …)
 * and stepper values that progressively change: { stepper: '20%' }
 * means pos 0 = 100%, pos ±1 = 80%, pos ±2 = 60%, etc.
 *
 * @param {object|null} styles — itemStyle config map
 * @param {HTMLElement[]} panels
 * @param {number} active — current index
 * @param {number} count
 * @param {boolean} loop
 * @param {HTMLElement[]} clones
 * @param {boolean} hasClones
 */
export function applyItemStyle(styles, panels, active, count, loop, clones, hasClones) {
    if (!styles) return;

    const styleAt = (panel, i) => {
        // Calculate relative position from active
        let rel = i - active;
        if (loop && count > 0) {
            // Shortest path in loop mode
            if (rel > count / 2) rel -= count;
            else if (rel < -count / 2) rel += count;
        }

        // Find the matching style rule
        const rule = styles[rel] ?? styles[String(rel)];
        const absRel = Math.abs(rel);

        if (!rule && absRel === 0) return;

        // Build computed styles for this panel
        const computed = {};

        // First, process position-0 rules for stepper values
        const baseRule = styles[0] ?? styles['0'];
        if (baseRule) {
            for (const [prop, val] of Object.entries(baseRule)) {
                if (val && typeof val === 'object' && val.stepper) {
                    const stepPct = parseFloat(val.stepper) / 100;
                    const factor = Math.max(0, 1 - stepPct * absRel);
                    if (prop === 'opacity') {
                        computed[prop] = String(factor);
                    } else if (prop === 'height') {
                        computed[prop] = (factor * 100) + '%';
                    } else {
                        computed[prop] = String(factor);
                    }
                } else if (absRel === 0) {
                    computed[prop] = val;
                }
            }
        }

        // Then, override with exact position rules (non-stepper values)
        if (rule) {
            for (const [prop, val] of Object.entries(rule)) {
                if (val && typeof val === 'object' && val.stepper) continue;
                computed[prop] = val;
            }
        }

        // Apply computed styles
        for (const [prop, val] of Object.entries(computed)) {
            razyui(panel).css(prop, val);
        }

        // For panels with no matching rule and no stepper, clear itemStyle props
        if (!rule && !baseRule) {
            razyui(panel).css({ transform: '', opacity: '', height: '' });
        }
    };

    panels.forEach((panel, i) => styleAt(panel, i));

    // Apply itemStyle to clones so loop boundary edges look correct
    if (hasClones && clones) {
        styleAt(clones[0], count - 1);   // lastClone mirrors last panel
        styleAt(clones[1], 0);            // firstClone mirrors first panel
    }
}

// ═══════════════════════════════════════════════
//  Focus Mode (scroll hijack)
// ═══════════════════════════════════════════════

/**
 * Initialize focus mode — wraps the container in a tall sentinel
 * and maps page scroll progress to panel index.
 *
 * @param {HTMLElement} container
 * @param {object} cfg
 * @param {number} count — total panel count
 * @param {Function} goFn — `(targetIndex) => void`  called when index should change
 * @param {Function} clampFn — `razyui.clamp`
 * @returns {{ wrapper, onScroll, onResize, isFocusActive }} — refs for destroy cleanup
 */
export function initFocus(container, cfg, count, goFn, clampFn) {
    const isFullpage = cfg.focus === 'fullpage';
    const align = cfg.focus === 'center' ? 'center' : 'top';

    // Wrap the container in a tall sentinel so the page has scroll room
    const wrapper = razyui.el('div', { className: 'swipe-focus-wrapper' });
    PART.FOCUS_WRAPPER.apply(wrapper);
    razyui(container).before(wrapper);
    wrapper.append(container);

    // position:sticky is broken when any ancestor has overflow other than
    // 'visible'.  Walk up and force overflow:visible, saving originals so
    // cleanupFocus can restore them.
    const overflowOverrides = [];
    let ancestor = wrapper[0].parentElement;
    while (ancestor && ancestor !== document.documentElement) {
        const cs = getComputedStyle(ancestor);
        if (cs.overflow !== 'visible' || cs.overflowX !== 'visible' || cs.overflowY !== 'visible') {
            overflowOverrides.push({
                el: ancestor,
                overflow: ancestor.style.overflow,
                overflowX: ancestor.style.overflowX,
                overflowY: ancestor.style.overflowY,
            });
            ancestor.style.overflow = 'visible';
            ancestor.style.overflowX = 'visible';
            ancestor.style.overflowY = 'visible';
        }
        ancestor = ancestor.parentElement;
    }

    // Fullpage — container and panels fill the viewport
    if (isFullpage) {
        razyui(container).addClass('swipe-fullpage');
        wrapper.addClass('swipe-focus-fullbleed');
        PART.FOCUS_FULLBLEED.apply(wrapper);
    }

    const getViewportH = () => {
        return window.visualViewport ? window.visualViewport.height : window.innerHeight;
    };

    const setWrapperHeight = () => {
        const vh = getViewportH();
        const offset = isFullpage
            ? parseInt(getComputedStyle(container).getPropertyValue('--swipe-offset') || '0', 10) || 0
            : 0;
        const slideH = vh - offset;
        wrapper.css('height', slideH * count + 'px');

        if (isFullpage) {
            razyui(container).css('height', slideH + 'px');

            // Force the track to match so grid children get a definite height
            const $track = razyui(container).find('.swipe-track');
            if ($track.length) $track.css('height', slideH + 'px');

            const vw = document.documentElement.clientWidth;
            wrapper.css({ 'margin-left': '0', width: '' });
            const naturalLeft = wrapper.getRect().left;
            wrapper.css({ width: vw + 'px', 'margin-left': -naturalLeft + 'px' });
        }
    };
    setWrapperHeight();

    // Sticky the container inside the wrapper
    const $ct = razyui(container);
    $ct.css('position', 'sticky');
    if (isFullpage) {
        const offset = parseInt(getComputedStyle(container).getPropertyValue('--swipe-offset') || '0', 10) || 0;
        $ct.css('top', offset ? offset + 'px' : '0');
    } else if (align === 'center') {
        $ct.css('top', `calc(50vh - ${container.offsetHeight / 2}px)`);
    } else {
        $ct.css('top', '0');
    }

    let focusActive = false;

    const onScroll = () => {
        const rect = wrapper.getRect();
        const wh = wrapper.prop('offsetHeight');
        const vh = window.innerHeight;
        const scrolled = -rect.top;

        if (scrolled < 0 || scrolled > wh) {
            focusActive = false;
            return;
        }

        focusActive = true;

        const scrollable = wh - vh;
        if (scrollable <= 0) return;

        const progress = clampFn(scrolled / scrollable, 0, 1);
        const targetIndex = Math.min(count - 1, Math.floor(progress * count));
        goFn(targetIndex);
    };

    onScroll();   // sync immediately

    return {
        wrapper,
        overflowOverrides,
        onScroll,
        onResize: setWrapperHeight,
        isFocusActive: () => focusActive,
    };
}

// ═══════════════════════════════════════════════
//  Destroy Helpers
// ═══════════════════════════════════════════════

/**
 * Remove all DOM modifications from panels and unwrap the track.
 *
 * @param {HTMLElement[]} panels
 * @param {HTMLElement} container
 * @param {HTMLElement} track
 */
export function cleanupPanels(panels, container, track) {
    panels.forEach(p => {
        const $p = razyui(p);
        $p.removeClass('swipe-panel swipe-card-panel is-active is-peek-in is-peek-out');
        $p.removeAttr('aria-hidden');
        $p.css({
            flex: '', opacity: '', transform: '', transformOrigin: '',
            backfaceVisibility: '', zIndex: '', transition: '',
            position: '', left: '', top: '', width: '', height: '',
        });
        delete p._swipeDuration;
        delete p._swipeEasing;
        razyui(track[0]).before($p);
    });
    track[0].remove();
}

/**
 * Tear down focus-mode wrapper.
 *
 * @param {HTMLElement} container
 * @param {HTMLElement} wrapper
 */
export function cleanupFocus(container, wrapper, overflowOverrides) {
    const $ct = razyui(container);
    $ct.removeClass('swipe-fullpage');
    $ct.css({ position: '', top: '', height: '', width: '' });
    const $track = $ct.find('.swipe-track');
    if ($track.length) $track.css('height', '');
    wrapper.before($ct);
    wrapper[0].remove();

    // Restore ancestor overflow values
    if (overflowOverrides) {
        for (const entry of overflowOverrides) {
            entry.el.style.overflow = entry.overflow;
            entry.el.style.overflowX = entry.overflowX;
            entry.el.style.overflowY = entry.overflowY;
        }
    }
}
