// ── Built-in effect renderers ───────────────────
// Each receives (panels[], activeIndex, direction, containerEl, config, animate).
// They apply inline styles. 'slide' is handled by the track transform — no per-panel work.

export const EFFECTS = Object.freeze({
    /** Default — track transform handles everything */
    slide: null,

    /** Cross-fade: stack all panels absolute, fade active to 1 */
    fade(panels, index, dir, container, cfg, animate) {
        panels.forEach((p, i) => {
            const dur = p._swipeDuration ?? 300;
            const ease = p._swipeEasing ?? 'ease-out';
            razyui(p).css({
                opacity: i === index ? '1' : '0',
                transition: animate !== false ? `opacity ${dur}ms ${ease}` : 'none',
            });
        });
    },

    /**
     * Stack: upcoming card slides in and covers the active panel.
     * Supports `stackDirection`: 'right' | 'left' | 'top' | 'bottom' (default derives from direction).
     */
    stack(panels, index, dir, container, cfg, animate) {
        const stackDir = cfg?.stackDirection
            || (dir === 'horizontal' ? 'right' : 'bottom');
        const translateMap = {
            right:  'translate3d(100%, 0, 0)',
            left:   'translate3d(-100%, 0, 0)',
            top:    'translate3d(0, -100%, 0)',
            bottom: 'translate3d(0, 100%, 0)',
        };
        const offScreen = translateMap[stackDir] || translateMap.right;

        panels.forEach((p, i) => {
            const diff = i - index;
            const $p = razyui(p);
            const dur = p._swipeDuration ?? 300;
            const ease = p._swipeEasing ?? 'ease-out';
            if (diff <= 0) {
                // Passed or active — stationary at centre, stacked by order
                $p.css({
                    transform: 'translate3d(0, 0, 0)',
                    opacity: '1',
                    zIndex: String(panels.length + diff),
                });
            } else {
                // Upcoming — off-screen in configured direction, above active
                $p.css({
                    transform: offScreen,
                    opacity: '1',
                    zIndex: String(panels.length + diff),
                });
            }
            $p.css('transition', animate !== false
                ? `transform ${dur}ms ${ease}` : 'none');
        });
    },

    /**
     * Flip: card-style page flip with hinge on the leading edge.
     * Departing panel flips away (0 → −180°), incoming panel flips in (180° → 0).
     */
    flip(panels, index, dir, container, cfg, animate) {
        const isH = dir === 'horizontal';
        panels.forEach((p, i) => {
            const diff = i - index;
            const $p = razyui(p);
            const dur = p._swipeDuration ?? 300;
            const ease = p._swipeEasing ?? 'ease-out';

            // Hinge on the leading edge
            $p.css({
                transformOrigin: isH ? 'left center' : 'center top',
                backfaceVisibility: 'hidden',
            });

            if (diff < 0) {
                // Already turned — flipped past hinge, backface hidden → invisible.
                // High z so the departing page flips OVER the active panel.
                $p.css({
                    transform: isH
                        ? 'perspective(1200px) rotateY(-180deg)'
                        : 'perspective(1200px) rotateX(180deg)',
                    zIndex: String(panels.length + 1),
                });
            } else if (diff === 0) {
                // Active — flat, facing the viewer
                $p.css({
                    transform: isH
                        ? 'perspective(1200px) rotateY(0deg)'
                        : 'perspective(1200px) rotateX(0deg)',
                    zIndex: String(panels.length),
                });
            } else {
                // Upcoming — flat behind active, revealed when active flips away
                $p.css({
                    transform: isH
                        ? 'perspective(1200px) rotateY(0deg)'
                        : 'perspective(1200px) rotateX(0deg)',
                    zIndex: String(Math.max(0, panels.length - diff)),
                });
            }
            // All panels stay at full opacity — visibility is controlled
            // by backfaceVisibility + z-index stacking, not opacity.
            $p.css('opacity', '1');
            $p.css('transition', animate !== false
                ? `transform ${dur}ms ${ease}` : 'none');
        });
    },
});