/**
 * @fileoverview Swipe helpers — pure utility functions.
 * @module module/Swipe/helpers
 */

import { EFFECTS, DOT_ABBR, JIT_SPACING_KEYS } from './constants.js';
import razyui from '../../index.js';

// ── Config resolution ───────────────────────────

/**
 * Resolve JIT spacing tokens in config keys to numeric px values.
 *
 * @param {object} config — mutable config object
 * @param {Function} spacePxFn — `razyui.JIT.TOKEN.spacePx`
 */
export function resolveJITTokens(config, spacePxFn) {
    JIT_SPACING_KEYS.forEach(k => {
        if (config[k] != null) {
            config[k] = spacePxFn(config[k]);
        }
    });
}

/**
 * Resolve the `effect` config value to internal flags.
 *
 * @param {string|Function} eff — config.effect value
 * @param {object} razyui — razyui core reference
 * @returns {{ effect: Function|null, isSlide: boolean, isCard: boolean, isSnap: boolean }}
 */
export function resolveEffect(eff, razyui) {
    if (eff === 'card')  return { effect: null, isSlide: false, isCard: true,  isSnap: false };
    if (eff === 'snap')  return { effect: null, isSlide: false, isCard: false, isSnap: true  };
    if (razyui.isFn(eff))  return { effect: eff,  isSlide: false, isCard: false, isSnap: false };
    if (razyui.isStr(eff) && eff !== 'slide' && EFFECTS[eff]) {
        return { effect: EFFECTS[eff], isSlide: false, isCard: false, isSnap: false };
    }
    return { effect: null, isSlide: true, isCard: false, isSnap: false };
}

// ── Size calculations ───────────────────────────

/**
 * Get the container size along the swipe direction.
 *
 * @param {HTMLElement} container
 * @param {string} direction — 'horizontal' | 'vertical'
 * @returns {number}
 */
export function getContainerSize(container, direction) {
    return direction === 'horizontal' ? container.offsetWidth : container.offsetHeight;
}

/**
 * Compute effective panel size.
 *
 * @param {number} contSize — container dimension in px
 * @param {object} cfg — config object
 * @returns {number}
 */
export function getPanelSize(contSize, cfg) {
    if (cfg.perView > 1) {
        return (contSize - (cfg.perView - 1) * cfg.gap) / cfg.perView;
    }
    return contSize - cfg.peek * 2 - cfg.peekGap * 2;
}

/**
 * Compute step size (panel + spacing).
 *
 * @param {number} pnlSize — panel size in px
 * @param {object} cfg
 * @returns {number}
 */
export function getStepSize(pnlSize, cfg) {
    if (cfg.perView > 1) return pnlSize + cfg.gap;
    return pnlSize + cfg.gap + cfg.peekGap;
}

/**
 * Compute track translate offset for a given track index.
 *
 * @param {number} trackIdx — position index in the track
 * @param {object} cfg
 * @param {number} stpSize — step size in px
 * @param {number} count — total panel count
 * @returns {number}
 */
export function getOffsetFor(trackIdx, cfg, stpSize, count) {
    if (cfg.perView > 1) {
        // When all panels fit, no scrolling needed
        if (cfg.perView >= count) return 0;
        return -trackIdx * stpSize;
    }
    return cfg.peek + cfg.peekGap - trackIdx * stpSize;
}

// ── Card mode calculations ──────────────────────

/**
 * Compute card mode metadata: effective columns, step, page count.
 *
 * @param {object} cfg
 * @param {number} containerW — container width in px
 * @param {number} count — total card count
 * @returns {{ cardCols: number, cardStep: number, cardPageCount: number }}
 */
export function cardComputeMeta(cfg, containerW, count) {
    const gap  = cfg.cardGap;
    const peek = cfg.cardPeek;
    let cardCols;

    if (cfg.cardWidth > 0) {
        const usable = containerW - peek * 2;
        cardCols = Math.max(1, Math.floor((usable + gap) / (cfg.cardWidth + gap)));
    } else {
        cardCols = Math.max(1, cfg.columns);
    }

    const cardStep = cfg.cardSwipe === 'single' ? 1 : cardCols;
    const cardPageCount = Math.max(1, Math.ceil((count - cardCols) / cardStep) + 1);

    return { cardCols, cardStep, cardPageCount };
}

/**
 * Compute card layout info: card width, effective peek, per-card positions, total width.
 *
 * @param {object} cfg
 * @param {number} containerW
 * @param {number} count
 * @param {number} cols — effective columns
 * @returns {{ cardW: number, effectivePeek: number, positions: number[], totalW: number }}
 */
export function cardLayoutInfo(cfg, containerW, count, cols) {
    const gap  = cfg.cardGap;
    const peek = cfg.cardPeek;

    let cardW;
    if (cfg.cardWidth > 0) {
        cardW = cfg.cardWidth;
    } else {
        const usable = containerW - peek * 2;
        cardW = (usable - gap * (cols - 1)) / cols;
    }

    let effectivePeek = peek;
    if (cfg.cardWidth > 0) {
        const occupiedByCards = cols * cardW + (cols - 1) * gap;
        effectivePeek = Math.max(0, (containerW - occupiedByCards) / 2);
    }

    const positions = [];
    for (let i = 0; i < count; i++) {
        positions[i] = effectivePeek + i * (cardW + gap);
    }

    const totalW = effectivePeek * 2 + count * cardW + (count - 1) * gap;

    return { cardW, effectivePeek, positions, totalW };
}

/**
 * Compute card track offset for a given page index.
 *
 * @param {number} pageIndex
 * @param {object} cfg
 * @param {number} containerW
 * @param {number} count
 * @param {number} cardCols
 * @param {number} cardStep
 * @param {Function} clampFn — `razyui.clamp`
 * @returns {number} — offset value (negative for scrolling right)
 */
export function cardOffsetFor(pageIndex, cfg, containerW, count, cardCols, cardStep, clampFn) {
    const gap  = cfg.cardGap;
    const peek = cfg.cardPeek;

    let cardW;
    if (cfg.cardWidth > 0) {
        cardW = cfg.cardWidth;
    } else {
        const usable = containerW - peek * 2;
        cardW = (usable - gap * (cardCols - 1)) / cardCols;
    }

    const pageOffset   = pageIndex * cardStep * (cardW + gap);
    const totalTrackW  = count * (cardW + gap) - gap;

    let effectivePeek = peek;
    if (cfg.cardWidth > 0) {
        const occupied = cardCols * cardW + (cardCols - 1) * gap;
        effectivePeek = Math.max(0, (containerW - occupied) / 2);
    }

    const maxOffset = totalTrackW + effectivePeek * 2 - containerW;
    return -clampFn(pageOffset, 0, maxOffset);
}

// ── Snap mode calculations ──────────────────────

/**
 * Compute center position of each panel relative to track start.
 *
 * @param {HTMLElement[]} panels
 * @param {string} direction
 * @param {number} gap
 * @returns {number[]}
 */
export function snapComputePositions(panels, direction, gap) {
    const isH = direction === 'horizontal';
    const positions = [];
    let offset = 0;

    panels.forEach((p, i) => {
        const size = isH ? p.offsetWidth : p.offsetHeight;
        const center = offset + size / 2;
        positions[i] = center;
        offset += size + gap;
    });

    return positions;
}

/**
 * Calculate snap offset to center-align the panel at `index`.
 *
 * @param {number} index
 * @param {number} containerSz
 * @param {number[]} snapPositions
 * @returns {number}
 */
export function snapOffsetFor(index, containerSz, snapPositions) {
    const panelCenter = snapPositions[index] || 0;
    return containerSz / 2 - panelCenter;
}

/**
 * Find the panel whose center is closest to the container center.
 *
 * @param {number} trackOffset — current track translate value
 * @param {number} containerSz — container size in swipe direction
 * @param {number[]} snapPositions — center positions
 * @returns {number} closest panel index
 */
export function snapFindClosest(trackOffset, containerSz, snapPositions) {
    const containerCenter = containerSz / 2;
    let closest = 0;
    let minDist = Infinity;

    snapPositions.forEach((center, i) => {
        const dist = Math.abs((center + trackOffset) - containerCenter);
        if (dist < minDist) {
            minDist = dist;
            closest = i;
        }
    });

    return closest;
}

// ── Misc helpers ────────────────────────────────

/**
 * Get dot-position CSS class from a position string.
 *
 * @param {string|false} pos — e.g. 'bottom-center'
 * @returns {string|null} — e.g. 'swipe-dots-bc', or null
 */
export function dotPositionClass(pos) {
    if (!pos || pos === false) return null;
    const parts = pos.split('-');
    if (parts.length === 2 && DOT_ABBR[parts[0]] && DOT_ABBR[parts[1]]) {
        return `swipe-dots-${DOT_ABBR[parts[0]]}${DOT_ABBR[parts[1]]}`;
    }
    return null;
}

/**
 * Create a clone of a panel element for infinite loop mode.
 *
 * @param {HTMLElement} el — panel to clone
 * @param {object} cfg — component config
 * @returns {HTMLElement}
 */
export function makeClone(el, cfg) {
    const clone = el.cloneNode(true);
    const $clone = razyui(clone);
    $clone.addClass('swipe-clone')
          .setAttr({ 'aria-hidden': 'true' })
          .removeAttr('id');
    $clone.find('[id]').removeAttr('id');

    if (cfg.perView > 1) {
        const totalGap = (cfg.perView - 1) * cfg.gap;
        $clone.css('flex', `0 0 calc((100% - ${totalGap}px) / ${cfg.perView})`);
    } else if (cfg.peek > 0) {
        const totalInset = cfg.peek * 2 + cfg.peekGap * 2;
        $clone.css('flex', `0 0 calc(100% - ${totalInset}px)`);
    }

    clone._swipeDuration = cfg.duration;
    clone._swipeEasing   = cfg.easing;
    return clone;
}
