/**
 * @fileoverview Swipe events — centralised event binding via AbortController.
 * @module module/Swipe/events
 */

import razyui from '../../index.js';

// ═══════════════════════════════════════════════
//  Default-mode drag (pointer / touch)
// ═══════════════════════════════════════════════

/**
 * Bind pointer and touch drag events for the default slide mode.
 *
 * @param {HTMLElement} track
 * @param {object} callbacks
 *   onStart(e), onMove(e), onEnd()
 * @returns {AbortController}
 */
export function bindDrag(track, callbacks) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const $track  = razyui(track);
    const $window = razyui(window);

    $track.on('pointerdown', callbacks.onStart, opts);
    $window.on('pointermove', callbacks.onMove, { ...opts, passive: false });
    $window.on('pointerup', callbacks.onEnd, opts);

    $track.on('touchstart', callbacks.onStart, { ...opts, passive: true });
    $window.on('touchmove', callbacks.onMove, { ...opts, passive: false });
    $window.on('touchend', callbacks.onEnd, opts);

    $track.on('dragstart', e => e.preventDefault(), opts);

    return ac;
}

