// ═══════════════════════════════════════════════
//  Wheel events (default mode)
// ═══════════════════════════════════════════════

/**
 * Bind wheel events for the default mode.
 *
 * @param {HTMLElement} container
 * @param {object} cfg — { direction, threshold }
 * @param {object} callbacks
 *   onStopAuto(), onNext(), onPrev(), onStartAuto(), isDestroyed(),
 *   getPanelSize()
 * @returns {AbortController}
 */
export function bindWheel(container, cfg, callbacks) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    let wheelDelta = 0;
    let wheelTimer = 0;

    razyui(container).on('wheel', (e) => {
        if (callbacks.isDestroyed()) return;
        callbacks.onStopAuto();

        const isH  = cfg.direction === 'horizontal';
        const delta = isH ? (e.deltaX || e.deltaY) : e.deltaY;

        wheelDelta += delta;

        clearTimeout(wheelTimer);
        wheelTimer = setTimeout(() => {
            const size = callbacks.getPanelSize();
            const threshold = size * cfg.threshold;

            if (Math.abs(wheelDelta) > threshold) {
                if (wheelDelta > 0) callbacks.onNext();
                else callbacks.onPrev();
            }
            wheelDelta = 0;
            callbacks.onStartAuto();
        }, 80);

        e.preventDefault();
    }, { ...opts, passive: false });

    return ac;
}

// ═══════════════════════════════════════════════
