// ═══════════════════════════════════════════════
//  Keyboard
// ═══════════════════════════════════════════════

/**
 * Bind keyboard navigation on the container.
 *
 * @param {HTMLElement} container
 * @param {object} cfg — { direction }
 * @param {object} callbacks
 *   onPrev(), onNext(), onGoFirst(), onGoLast(), isDestroyed()
 * @returns {AbortController}
 */
export function bindKeyboard(container, cfg, callbacks) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const isH  = cfg.direction === 'horizontal';

    razyui(container).setAttr({ tabindex: '0' });

    razyui(container).on('keydown', (e) => {
        if (callbacks.isDestroyed()) return;
        // Only respond when container or its child is focused
        if (!container.contains(document.activeElement) &&
            document.activeElement !== container) return;

        const back = isH ? 'ArrowLeft' : 'ArrowUp';
        const fwd  = isH ? 'ArrowRight' : 'ArrowDown';

        if (e.key === back)       { e.preventDefault(); callbacks.onPrev(); }
        else if (e.key === fwd)   { e.preventDefault(); callbacks.onNext(); }
        else if (e.key === 'Home') { e.preventDefault(); callbacks.onGoFirst(); }
        else if (e.key === 'End')  { e.preventDefault(); callbacks.onGoLast(); }
    }, opts);

    return ac;
}

// ═══════════════════════════════════════════════
//  Dot click (shared)
// ═══════════════════════════════════════════════

/**
 * Bind click delegation on dot container.
 *
 * @param {HTMLElement} dotsEl
 * @param {Function} onDotClick — `(index) => void`
 * @returns {AbortController}
 */
export function bindDotClick(dotsEl, onDotClick) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };
    const raw  = dotsEl[0] || dotsEl;

    razyui(raw).on('click', (e) => {
        const dot = razyui(e.target).closest('.swipe-dot');
        if (!dot.length) return;
        const idx = Array.from(raw.children).indexOf(dot[0]);
        if (idx >= 0) onDotClick(idx);
    }, opts);

    return ac;
}

// ═══════════════════════════════════════════════
//  Button clicks
// ═══════════════════════════════════════════════

/**
 * Bind click events on prev / next buttons.
 *
 * @param {HTMLElement} prevBtn
 * @param {HTMLElement} nextBtn
 * @param {object} callbacks — { onPrev(), onNext() }
 * @returns {AbortController}
 */
export function bindButtonClicks(prevBtn, nextBtn, callbacks) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $prevBtn = razyui(prevBtn);
    const $nextBtn = razyui(nextBtn);

    $prevBtn.on('click', callbacks.onPrev, opts);
    $nextBtn.on('click', callbacks.onNext, opts);

    return ac;
}

// ═══════════════════════════════════════════════
//  perView click-to-select
// ═══════════════════════════════════════════════

/**
 * Bind click-to-select on panels when perView >= count.
 *
 * @param {HTMLElement[]} panels
 * @param {Function} onSelect — `(index) => void`
 * @returns {AbortController}
 */
export function bindPerViewClick(panels, onSelect) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    panels.forEach((panel, i) => {
        razyui(panel).css('cursor', 'pointer');
        razyui(panel).on('click', () => onSelect(i), opts);
    });

    return ac;
}

// ═══════════════════════════════════════════════
//  Focus-mode window listeners
// ═══════════════════════════════════════════════

/**
 * Bind focus-mode window scroll and resize listeners.
 *
 * @param {Function} onScroll — scroll handler from initFocus
 * @param {Function} onResize — resize handler from initFocus
 * @returns {AbortController}
 */
export function bindFocusScroll(onScroll, onResize) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $window = razyui(window);

    $window.on('scroll', onScroll, { ...opts, passive: true });
    $window.on('resize', onResize, opts);

    return ac;
}
